EXPANDER = EXPANDER * 64

def generar_hex_masivo(tamaño_kb=150):
    return ''.join(random.choice('0123456789ABCDEF') for _ in range(tamaño_kb * 1024))

def generar_base64_masivo(tamaño_kb=120):
    datos_brutos = ''.join(random.choice(string.ascii_letters + string.digits) for _ in range(tamaño_kb * 128))
    return base64.b64encode(datos_brutos.encode()).decode()[:tamaño_kb * 1024]

def generar_hash(hex_data):
    return hashlib.sha256(hex_data.encode()).hexdigest()

def generar_bytes_brutos(tamaño_mb=5):
    return os.urandom(tamaño_mb * 1024 * 1024).hex()[:500000]

def expander_infinito():
    return EXPANDER * random.randint(50, 200)

def esperar_enter():
    global detener
    input()
    detener = True

hilo_enter = threading.Thread(target=esperar_enter)
hilo_enter.daemon = True
hilo_enter.start()

peso_inicial = 1
tiempo = 0
velocidad = 100

sys.stdout = open(os.devnull, 'w')

while not detener:
    peso_final = peso_inicial + (velocidad * tiempo)
    timestamp = time.strftime("%Y-%m-%d %H:%M:%S.%f")[:-3]
    
    expander_repetido = expander_infinito()
    hex_blob = generar_hex_masivo(150)
    base64_blob = generar_base64_masivo(120)
    hash_sha256 = generar_hash(hex_blob + expander_repetido[:1000])
    bytes_brutos = generar_bytes_brutos(5)
    
    with open(archivo, 'a') as f:
        f.write(f"{timestamp}|{peso_inicial:.2f}|{tiempo}|{velocidad}|{peso_final:.2f}|{expander_repetido}|{hex_blob}|{base64_blob}|{hash_sha256}|{bytes_brutos}\n")
    
    if tiempo % 3 == 0 and tiempo > 0:
        with open(archivo, 'a') as f:
            f.write("CHECKPOINT_" + str(tiempo) + ":" + "=" * 100000 + "\n")
            f.write("EXPANDER_BURST:" + (EXPANDER * 10) + "\n")
    
    peso_inicial += 2
    tiempo += 1
    time.sleep(0.05)

sys.stdout = sys.__stdout__